changeSet.sql:
ALTER TYPE VariableOperation RENAME TO VariableOperation__;
CREATE TYPE VariableOperation as ENUM ('PLUS', 'MINUS', 'MULTIPLY', 'DIVIDE', 'OPEN_BRACKET', 'CLOSE_BRACKET', 'MIN', 'MAX', 'COMMA', 'ABS',
'MEDIAN', 'AVERAGE', 'MODE', 'SQRT', 'SUM', 'RAND',	'NONE');
ALTER TABLE metric_variables ALTER COLUMN operation_before type VariableOperation using operation_before::text::VariableOperation;
ALTER TABLE metric_variables ALTER COLUMN operation_after type VariableOperation using operation_after::text::VariableOperation;
ALTER TABLE metric_formula_items ALTER COLUMN operation type VariableOperation using operation::text::VariableOperation;
ALTER TABLE formula_items ALTER COLUMN operation type VariableOperation using operation::text::VariableOperation;
DROP TYPE VariableOperation__;
